import React from 'react';
import {
    MDBBtn,
    MDBContainer,
    MDBCard,
    MDBCardBody,
    MDBCardImage,
    MDBRow,
    MDBCol,
    MDBIcon,
    MDBInput
} from 'mdb-react-ui-kit';

import './styles.css';

const LogIn = () => {
    return (
        <MDBContainer fluid className="d-flex justify-content-center align-items-center min-vh-100 login-page-bg">
            <MDBCard className="rounded-4 shadow-lg overflow-hidden login-card" style={{ maxWidth: '900px' }}>
                <MDBRow className='g-0'>

                    <MDBCol md='6' className="login-image-container">
                        <MDBCardImage
                            src='https://mdbcdn.b-cdn.net/img/Photos/new-templates/bootstrap-login-form/img1.webp'
                            alt="login form"
                            className='w-100 h-100 object-fit-cover login-image'
                        />
                    </MDBCol>

                    <MDBCol md='6' className="d-flex align-items-center">
                        <MDBCardBody className='px-5'>

                            {/* <div className='d-flex flex-row align-items-center mb-4'>
                <MDBIcon fas icon="cubes fa-3x me-3" style={{ color: '#ff6219' }} />
                <span className="h1 fw-bold mb-0">Logo</span>
              </div> */}

                            <div className='d-flex justify-content-center mb-4'>
                                <img
                                    src="../assets/logo.jpeg" 
                                    alt="My College Vision Logo"
                                    className="img-fluid"
                                    style={{ maxHeight: '300px' }}
                                />
                            </div>


                            <h5 className="fw-normal mb-4" style={{ letterSpacing: '1px' }}>Sign into your account</h5>

                            <MDBInput wrapperClass='mb-4' label='Email address' type='email' size="lg" />
                            <MDBInput wrapperClass='mb-4' label='Password' type='password' size="lg" />

                            <MDBBtn className="mb-4 w-100 login-btn" color='dark' size='lg'>
                                LOGIN
                            </MDBBtn>

                            <div className="text-center">
                                <a className="small text-muted" href="#!">Forgot password?</a>
                                <p className="mt-3 mb-0">
                                    Don't have an account? <a href="#!" className="fw-bold text-decoration-none" style={{ color: '#393f81' }}>Register here</a>
                                </p>
                            </div>

                            <div className='d-flex justify-content-center mt-4'>
                                <a href="#!" className="small text-muted me-3">Terms of use</a>
                                <a href="#!" className="small text-muted">Privacy policy</a>
                            </div>

                        </MDBCardBody>
                    </MDBCol>

                </MDBRow>
            </MDBCard>
        </MDBContainer>
    );
}

export default LogIn;
